const html = $input.first().json.data || $input.first().json;
const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);

// Extract the embedded REPORT_DATA JSON from the script tag
const match = htmlStr.match(/const REPORT_DATA = (\{[\s\S]+?\});[\s\n]*\/\//);
if (!match) {
  // Try alternate pattern
  const match2 = htmlStr.match(/const REPORT_DATA = (\{[\s\S]+?\})\s*\n\s*\/\//);
  if (!match2) throw new Error('REPORT_DATA not found in CSOV page');
}

let reportData;
try {
  reportData = JSON.parse(match ? match[1] : match2[1]);
} catch(e) {
  throw new Error('Failed to parse REPORT_DATA: ' + e.message);
}

// Extract key metrics
const csov = reportData.csov_score || 0;
const prev = reportData.previous_csov_score || 0;
const components = reportData.components || {};
const actionItems = reportData.action_items || reportData.serp_action_items || [];
const countryBreakdown = reportData.countries || {};
const weekLabel = reportData.week_label || reportData.date_label || '';

// Build a compact summary for Claude
const summary = {
  csov_score: csov,
  prev_csov_score: prev,
  delta: +(csov - prev).toFixed(2),
  week: weekLabel,
  components: {
    serp: components.serp?.score || 0,
    ai_overview: components.ai_overview?.score || 0,
    llm: components.llm?.score || 0,
    earned_media: components.earned_media?.score || 0,
  },
  serp_negative_count: components.serp?.negative || 0,
  serp_positive_count: components.serp?.positive || 0,
  weakest_countries: Object.entries(countryBreakdown || {})
    .sort((a,b) => (a[1].total||0) - (b[1].total||0))
    .slice(0,3)
    .map(([k,v]) => ({country: k, score: v.total || 0})),
  action_items: actionItems.slice(0,10),
};

return [{ json: { summary, raw: reportData } }];

const response = $input.first().json;
const text = response.content?.[0]?.text || '';

let recommendations;
try {
  // Strip any accidental markdown code fences
  const cleaned = text.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  recommendations = JSON.parse(cleaned);
} catch(e) {
  // Fallback if Claude didn't return clean JSON
  recommendations = {
    next_steps: [
      "Review and respond to the Reddit thread 'Was using ivisa a mistake' — it's ranking #1 for multiple reputation keywords.",
      "Publish a Social Proof carousel featuring verified Trustpilot reviews on Instagram and TikTok.",
      "Create an Educational post explaining how iVisa's service fee saves time and prevents costly errors.",
      "Publish a Security & Privacy explainer post addressing data handling concerns surfaced in AI Overviews.",
      "Pitch a travel blogger or YouTuber to publish an honest iVisa review — earned media score needs third-party lift."
    ],
    content_ideas: [
      {"icon":"🛡️","title":"'Why we charge a fee' — transparent breakdown","detail":"Short-form video explaining the value behind the fee. Address AI Overview criticism directly.","pillar":"Educational","platforms":["TikTok","Instagram","YouTube"],"priority":"high"},
      {"icon":"⭐","title":"Customer wins compilation","detail":"Carousel of real Trustpilot reviews with visa approval photos. Counter negative Reddit sentiment.","pillar":"Social Proof","platforms":["Instagram","Facebook","LinkedIn"],"priority":"high"},
      {"icon":"🏛️","title":"iVisa vs government portals — side by side","detail":"Infographic showing how iVisa complements (not replaces) government visa processes.","pillar":"Educational","platforms":["Instagram","LinkedIn"],"priority":"high"},
      {"icon":"🔒","title":"Your data is safe — here's exactly how","detail":"Story or reel walking through iVisa's security certifications. Counter AI Overview data concerns.","pillar":"Educational","platforms":["Instagram","TikTok"],"priority":"medium"},
      {"icon":"😅","title":"Visa stress vs iVisa ease — relatable humor","detail":"Trending audio reel: chaotic government portal vs smooth iVisa flow. Humor/relatability pillar.","pillar":"Humor/Relatability/Entertainment","platforms":["TikTok","Instagram"],"priority":"medium"}
    ]
  };
}

const summary = $('Extract REPORT_DATA').first().json.summary;

return [{ json: {
  next_steps: recommendations.next_steps || [],
  content_ideas: recommendations.content_ideas || [],
  csov_score: summary.csov_score,
  prev_csov_score: summary.prev_csov_score,
  components: summary.components,
  generated_at: new Date().toISOString(),
}}];

const ghFile = $('GitHub GET data.json').first().json;
const sha = ghFile.sha;
const currentContent = Buffer.from(ghFile.content.replace(/\n/g,''), 'base64').toString('utf8');
let current = {};
try { current = JSON.parse(currentContent); } catch(e) { current = {}; }

const recs = $('Parse Recommendations').first().json;

// Update brand_reputation section with CSOV data + AI recommendations
const newData = {
  ...current,
  brand_reputation: {
    embed_url: (current.brand_reputation || {}).embed_url || 'https://paulavotobernales-94.github.io/-ivisa-csov/index.html',
    csov_score: recs.csov_score,
    prev_csov_score: recs.prev_csov_score,
    components: recs.components,
    next_steps: recs.next_steps,
    content_ideas: recs.content_ideas,
    last_updated: recs.generated_at,
  },
  // Also inject top content ideas into the content_ideas section
  content_ideas: {
    status: 'active',
    source: 'csov + manual',
    last_updated: recs.generated_at,
    ideas: recs.content_ideas,
  },
};
newData.meta = {
  ...current.meta,
  last_updated: new Date().toISOString(),
  generated_by: 'n8n + claude-ai',
};

const encoded = Buffer.from(JSON.stringify(newData, null, 2), 'utf8').toString('base64');
return [{ json: { content: encoded, sha } }];
